#!/bin/bash
# MongoDB Aggregation Pipeline Examples
set -euo pipefail

DB="mydb"

echo "=== Revenue by status ==="
mongosh --quiet --eval "
db.orders.aggregate([
  {$group: {
    _id: '$status',
    count: {$sum: 1},
    totalRevenue: {$sum: '$amount'},
    avgOrder: {$avg: '$amount'}
  }},
  {$sort: {totalRevenue: -1}}
]).forEach(doc => {
  print(doc._id + ': ' + doc.count + ' orders, $' + doc.totalRevenue.toFixed(2) + ' total, $' + doc.avgOrder.toFixed(2) + ' avg');
});
" "$DB"

echo ""
echo "=== Top 10 customers by spending ==="
mongosh --quiet --eval "
db.orders.aggregate([
  {$match: {status: 'completed'}},
  {$group: {_id: '$customerId', total: {$sum: '$amount'}, orders: {$sum: 1}}},
  {$sort: {total: -1}},
  {$limit: 10}
]).forEach(doc => {
  print(doc._id + ': $' + doc.total.toFixed(2) + ' (' + doc.orders + ' orders)');
});
" "$DB"

echo ""
echo "=== Monthly revenue trend ==="
mongosh --quiet --eval "
db.orders.aggregate([
  {$match: {status: 'completed'}},
  {$group: {
    _id: {$dateToString: {format: '%Y-%m', date: '$createdAt'}},
    revenue: {$sum: '$amount'},
    orders: {$sum: 1}
  }},
  {$sort: {_id: 1}}
]).forEach(doc => {
  print(doc._id + ': $' + doc.revenue.toFixed(2) + ' (' + doc.orders + ' orders)');
});
" "$DB"
